/// Simulates a tool registry with permission-requiring tools.
pub struct ToolRegistry {
    tools: Vec<ToolInfo>,
}

pub struct ToolInfo {
    pub name: String,
    pub requires_permission: bool,
    pub timeout_seconds: u64,
}

impl ToolRegistry {
    pub fn new() -> Self {
        Self {
            tools: vec![
                ToolInfo {
                    name: "bash".to_string(),
                    requires_permission: true,
                    timeout_seconds: 300,  // 5 minutes
                },
                ToolInfo {
                    name: "read_file".to_string(),
                    requires_permission: true,
                    timeout_seconds: 300,
                },
                ToolInfo {
                    name: "write_file".to_string(),
                    requires_permission: true,
                    timeout_seconds: 300,
                },
            ],
        }
    }

    pub fn get_timeout(&self, name: &str) -> Option<u64> {
        self.tools.iter()
            .find(|t| t.name == name)
            .map(|t| t.timeout_seconds)
    }
}
